// Cloud with a star in the clear sky above it — the moon-down counterpart of
// wi-night-alt-cloudy (no stock weather-icons glyph pairs a star with a cloud;
// composed from vendored subpaths, mirroring the old lucide CloudStar).
export function CloudStarIcon({ size = 19, style }: { size?: number; style?: React.CSSProperties }) {
  return (
    <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 30 30" fill="currentColor" style={{ flexShrink: 0, ...style }}>
      <path d={WI_PATHS['cloud']} />
      {/* sparkle moved from (7.7, 16.2) to the upper-right sky, clear of the cloud outline */}
      <path d={STAR_SPARKLE} transform="translate(15.6, -10.4)" />
    </svg>
  )
}

export function WiIcon({ name, size = 19, style }: { name: string; size?: number; style?: React.CSSProperties }) {
  const d = WI_PATHS[name]
  if (!d) return null
  return (
    <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 30 30" fill="currentColor" style={{ flexShrink: 0, ...style }}>
      <path d={d} />
    </svg>
  )
}

// Sky-state icon from cloud cover % alone — shared by the WMO-code path (codes 0-3, where
// cloud_cover_pct is more precise than the coarse API code) and the no-code fallback path
// (providers, like 7Timer, that never supply a WMO code at all). Clear and partly-cloudy
// tiers both distinguish moon state: moon up shows the moon (clear crescent / behind the
// cloud), moon down shows stars — partly cloudy still leaves sky visible, so the icon
// should say what's in it. Only overcast drops the distinction.
export function skyIconFromCloudCover(cloudCover: number, moonUp: boolean, size: number) {
  if (cloudCover <= 25) return <WiIcon name={moonUp ? 'night-clear' : 'stars'} size={size} />
  if (cloudCover <= 65) {
    return moonUp
      ? <WiIcon name="night-alt-cloudy" size={size} />
      : <CloudStarIcon size={size} />
  }
  return <WiIcon name="cloudy" size={size} />
}

// WMO code → weather-icons name, for codes >= 4 (codes 0-3 use skyIconFromCloudCover
// instead, since cloud_cover_pct is more precise there). Fog (45/48) is deliberately
// absent — it renders as bold text in WmoIcon, not an icon.
export const WMO_ICON_NAMES: Record<number, string> = {
  51: 'showers', 53: 'showers', 55: 'showers',
  56: 'rain-mix', 57: 'rain-mix',
  61: 'rain', 63: 'rain', 65: 'rain-wind',
  66: 'rain-mix', 67: 'rain-mix',
  71: 'snow', 73: 'snow', 75: 'snow', 77: 'sleet',
  80: 'showers', 81: 'showers', 82: 'rain-wind',
  85: 'snow', 86: 'snow',
  95: 'thunderstorm', 96: 'thunderstorm', 99: 'thunderstorm',
}

// precip_type → weather-icons name, for providers that supply precip_type but no numeric
// WMO code (7Timer). "fog" is absent here too, same reason as WMO_ICON_NAMES above.
export const PRECIP_TYPE_ICON_NAMES: Record<string, string> = {
  frzr: 'rain-mix',
  icep: 'sleet',
  snow: 'snow',
  rain: 'rain',
  tstorm: 'thunderstorm',
}

// Transparency label for the combined Seeing/Transp column — the standard label as-is
// (not an abbreviation). Explicit map, not a passthrough, so any unexpected value from
// the provider (transparency is a generic string, not a strict union) still falls back
// gracefully via the `?? p.transparency` at the call site.
export const TRANSP_ABBR: Record<string, string> = {
  Excellent: 'Optimal',
  Good: 'Good',
  Fair: 'Fair',
  Poor: 'Poor',
}

// Seeing (arcsec, lower = better) → the same 4-tier scale as TRANSP_ABBR, so the two
// halves of the combined column read consistently ("Optimal / Good", not "Exc / Good").
export function seeingTier(arcsec: number): 'Optimal' | 'Good' | 'Fair' | 'Poor' {
  if (arcsec < 1.0) return 'Optimal'
  if (arcsec <= 1.5) return 'Good'
  if (arcsec <= 2.0) return 'Fair'
  return 'Poor'
}

export function WmoIcon({ code, cloudCover, moonUp = false, size = 32, aod, pm25, visibilityM, precipType, windSpeedMs, windGustMs, transparency }: {
  code: number | null; cloudCover?: number | null; moonUp?: boolean; size?: number
  aod?: number | null; pm25?: number | null; visibilityM?: number | null; precipType?: string | null
  windSpeedMs?: number | null; windGustMs?: number | null; transparency?: string | null
}) {
  // Fog and haze render as bold text, not an icon — both are visibility hazards easy to
  // misjudge from a small glyph at a glance; the word is unambiguous.
  if (precipType === 'fog') return <span className="wx-cond-word">Fog</span>

  const isNoPrecip = precipType == null || precipType === 'none'
  // Thresholds mirror rate_conditions()'s limiter curves: AOD 0.3 and PM2.5 35 µg/m³ are
  // both where the gentle taper gives way to the steep power-curve penalty. Checked
  // independently (not aod-priority) — a shallow, trapped surface smoke layer can read
  // hazardous on PM2.5 while satellite column AOD still looks moderate.
  const aodHazy = isNoPrecip && aod != null && aod > 0.3
  const pmHazy  = isNoPrecip && pm25 != null && pm25 > 35
  const visHazy = isNoPrecip && visibilityM != null && visibilityM < 10000 && visibilityM >= 1000
  // AOD is the column (satellite/model) measurement — an elevated-but-surface-clean
  // reading means the aerosol is aloft, decoupled from the ground. PM2.5 and horizontal
  // visibility are both near-surface measurements, so either one without AOD means the
  // haze is surface-coupled. Both together is the unqualified, worst-case "Haze".
  const surfaceHazy = pmHazy || visHazy
  // Cross-check: an AOD-only ("Aloft") reading is discarded when the independently
  // sourced (7Timer) transparency assessment already says Good or better — the two
  // would otherwise contradict each other in the same cell (AOD says hazy, transparency
  // says clear). Below that (Fair/Poor), the signals agree rather than conflict, so AOD
  // still gets to show. If transparency is unavailable at all (date outside 7Timer's
  // range, or the API is down), there's nothing to cross-check against — fall back to
  // the AOD signal alone rather than silently discarding a real reading for no reason.
  const transpContradicts = transparency === 'Excellent' || transparency === 'Good'
  const aloftConfirmed = aodHazy && !transpContradicts
  // "Hazy" describes a visible-but-degraded sky — once cloud cover crosses into the same
  // "cloudy" tier skyIconFromCloudCover uses for overcast, the sky isn't visible at all,
  // so the claim is moot regardless of what AOD/PM2.5 say underneath or above the deck.
  // Unlike the wind check below (which combines with cloud state instead of gating on
  // it), there's no meaningful "hazy AND overcast" icon — it's just overcast.
  const skyObscured = cloudCover != null && cloudCover > 25
  if (!skyObscured && (aloftConfirmed || surfaceHazy)) {
    const label = aloftConfirmed && surfaceHazy ? 'Haze' : aloftConfirmed ? 'Haze: Aloft' : 'Haze: Surface'
    const readings = [
      aod != null ? `AOD ${aod.toFixed(2)} (satellite column)` : null,
      pm25 != null ? `PM2.5 ${Math.round(pm25)} µg/m³ (surface)` : null,
      visibilityM != null ? `visibility ${Math.round(visibilityM / 1000)} km` : null,
    ].filter(Boolean).join(' · ')
    return (
      <InfoTip tip={<>Smoke / aerosol haze — dims stars and flattens contrast even under a cloudless sky. {readings}. Penalized in the hourly rating past AOD 0.3 or PM2.5 35.</>}>
        <span className="wx-cond-word">{label}</span>
      </InfoTip>
    )
  }

  // Wind/gust: only when there's no active precip (a rain/snow/fog icon already implies
  // wind may be part of it, e.g. wi-rain-wind). Two severities:
  //   "gusty"  — sustained OR gust crosses 20 mph (~8.94 m/s). This threshold is specific
  //              to the Conditions icon, deliberately decoupled from the Wind cell's own
  //              highlight threshold (6.3 m/s / ~14 mph, see windSevere/gustSevere below),
  //              which stays unchanged by design.
  //   "gate"   — the worse of sustained/gust reaches 17 m/s, the same cap where
  //              rate_conditions()'s wind limiter already hits zero (a de facto hard gate).
  // Gate takes priority over gusty when both are true. Needs cloudCover to pick between
  // the clear-sky and cloudy variants; skip entirely if cloud state is unknown.
  if (isNoPrecip && cloudCover != null) {
    const windValues = [windSpeedMs, windGustMs].filter((v): v is number => v != null)
    const effectiveWind = windValues.length ? Math.max(...windValues) : null
    const isGate  = effectiveWind != null && effectiveWind >= 17
    const isGusty = !isGate && effectiveWind != null && effectiveWind >= 8.94 // 20 mph
    const isClear = cloudCover <= 25
    if (isGate) return <WiIcon name={isClear ? 'strong-wind' : 'cloudy-windy'} size={size} />
    if (isGusty) return <WiIcon name={isClear ? 'strong-wind' : 'cloudy-gusts'} size={size} />
  }

  if (code != null) {
    // For pure sky-state codes (0–3), cloud cover % is more precise than the API code
    if (code <= 3 && cloudCover != null) return skyIconFromCloudCover(cloudCover, moonUp, size)
    const name = WMO_ICON_NAMES[code]
    if (name) return <WiIcon name={name} size={size} />
  }

  // No numeric WMO code available — e.g. 7Timer serving as full primary because the
  // Open-Meteo provider is down. It still supplies cloud_cover_pct and precip_type
  // directly, so fall back to those instead of rendering nothing.
  if (!isNoPrecip) {
    const name = PRECIP_TYPE_ICON_NAMES[precipType!]
    if (name) return <WiIcon name={name} size={size} />
  }
  if (cloudCover != null) return skyIconFromCloudCover(cloudCover, moonUp, size)
  return null
}

// Horizontal coordinates in the conventional order: azimuth (with compass point)
